	"os"
	"strings"
	"time"

	"github.com/AdRoll/goamz/v3/aws"
	"github.com/AdRoll/goamz/v3/s3"
)

var (
	flagRegion   = flag.String("region", "us-east-1", "AWS region")
	flagBucket   = flag.String("bucket", "", "S3 bucket name")
	flagKey      = flag.String("key", "", "S3 object key")
	flagFile     = flag.String("file", "", "Local file to upload")
	flagEndpoint = flag.String("endpoint", "", "S3 compatible service endpoint")
	flagInsecure = flag.Bool("insecure", false, "Skip TLS verification")
	flagDebug    = flag.Bool("debug", false, "Enable debug output")
)

func main() {
	flag.Parse()

	if *flagBucket == "" || *flagKey == "" {
		fmt.Fprintln(os.Stderr, "Error: bucket and key are required")
		flag.Usage()
		os.Exit(1)
	}

	// Get AWS credentials from environment
	auth, err := aws.EnvAuth()
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error getting AWS credentials:", err)
		os.Exit(1)
	}

	// Create S3 client
	regionName := *flagRegion
	if *flagEndpoint != "" {
		regionName = "custom-endpoint"
	}

	region := aws.Region{
		Name:                 regionName,
		S3Endpoint:           *flagEndpoint,
		S3BucketEndpoint:     "",
		S3LocationConstraint: false,
	}

	if *flagEndpoint != "" {
		region.S3Endpoint = *flagEndpoint
		region.S3BucketEndpoint = s3.MakeS3BucketEndpoint(*flagEndpoint)
	}

	client := s3.New(auth, region)

	// Enable debug if requested
	if *flagDebug {
		client.Debug = true
	}

	// Upload the file
	if *flagFile != "" {
		file, err := os.Open(*flagFile)
		if err != nil {
			fmt.Fprintln(os.Stderr, "Error opening file:", err)
			os.Exit(1)
		}
		defer file.Close()

		fileInfo, err := file.Stat()
		if err != nil {
			fmt.Fprintln(os.Stderr, "Error getting file info:", err)
			os.Exit(1)
		}

		headers := http.Header{}
		headers.Set("Content-Type", "application/octet-stream")

		err = client.Bucket(*flagBucket).PutReader(*flagKey, file, fileInfo.Size(), headers, s3.PublicRead)
		if err != nil {
			fmt.Fprintln(os.Stderr, "Error uploading file:", err)
			os.Exit(1)
		}

		fmt.Printf("Successfully uploaded %s to s3://%s/%s\n", *flagFile, *flagBucket, *flagKey)
		os.Exit(0)
	}

	// Download the object
	resp, err := client.Bucket(*flagBucket).Get(*flagKey)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error downloading object:", err)
		os.Exit(1)
	}
	defer resp.Body.Close()

	// Write to stdout or file
	_, err = io.Copy(os.Stdout, resp.Body)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error writing output:", err)
		os.Exit(1)
	}
}
